struct buf {
	uint32			dev;
	uint32			sectorno;	
	uint32			refcnt;
	uint16			valid;
	uint8			dirty;
	uint8			disk;
	struct d_list	list;
	list_node_t		hash;
	struct sleeplock	lock;
	uchar			data[BSIZE];
};

void binit(void) {
	initlock(&bcachelock, "bcache");
	dlist_init(&lru_head);
	for (int i = 0; i < BCACHE_TABLE_SIZE; i++) bcache[i] = NULL;
	for (struct buf *b = bufs; b < bufs + BNUM; b++) {
		b->refcnt = 0; b->dirty = 0; b->disk = 0;
		dlist_add_before(&lru_head, &b->list);
		initsleeplock(&b->lock, "buffer");
	}
}

struct buf* bget(uint dev, uint sectorno) {
	int idx = __hash_idx(sectorno);
	acquire(&bcachelock);
rescan:
	for (list_node_t *l = bcache[idx]; l != NULL; l = l->next) {
		b = container_of(l, struct buf, hash);
		if (b->dev == dev && b->sectorno == sectorno) { ... return b; }
	}
	// cache miss: evict from LRU tail
	struct d_list *dl = lru_head.prev;
	if (dl != &lru_head) {
		b = container_of(dl, struct buf, list);
		b->dev = dev; b->sectorno = sectorno; b->refcnt = 1;
		...
	}
}

int disk_read_block(struct superblock *sb, int usr, char *dst, uint64 sectorno, uint64 off, uint64 len) {
	struct buf *b = bread(sb->devnum, sectorno);
	ret = either_copyout_nocheck(usr, (uint64)dst, b->data + off, len);
	brelse(b);
}

int disk_write_block(struct superblock *sb, int usr, char *src, uint64 sectorno, uint64 off, uint64 len) {
	struct buf *b;
	if (off == 0 && len == BSIZE) b = bget(sb->devnum, sectorno);
	else b = bread(sb->devnum, sectorno);
	int ret = either_copyin_nocheck(b->data + off, usr, (uint64)src, len);
	bwrite(b);
}

int sdcard_submit(struct buf *b) {
	if (b->dirty == 0 && b->disk == 0) {
		dlist_add_before(&sd_wqueue.head, &b->list);
		res = 0x1; sd_wqueue_num++;
	}
	b->dirty = 1;
	...
}

void sdcard_write_start(void) {
	...
	b->disk = 1; b->dirty = 0;
	if (sdcard_multiple_write(b, nbuf) < 0) {
		b->disk = 0; b->dirty = 1;
	}
}

