static int handle_file_mmap(uint64 badaddr, struct seg *s) {
	struct file *fp = MMAP_FILE(s->mmap);
	struct inode *ip = fp->ip;
	uint64 off = s->f_off + (PGROUNDDOWN(badaddr) - s->addr);
	struct mmap_page *map;
	...
	acquire(&ip->ilock);
	map = get_mmap_with_parent(&ip->mapping, off, &parent, &plink);
	if (share) {
		if (map->pa == NULL) {
			pa = allocpage();
			pagereg((uint64)pa, 1);
			map->pa = pa;
		}
		...
		ilock(ip);
		if (!map->valid) {
			__page_file_read(ip, off, (uint64)pa);
			map->valid = 1;
		}
		iunlock(ip);
	}
}

uint64 sys_mmap(void) {
  uint64 start, len; int prot, flags, fd; int64 off; struct file *f = NULL;
  argaddr(0, &start); argaddr(1, &len); argint(2, &prot); argint(3, &flags);
  argfd(4, &fd, &f); argaddr(5, (uint64*)&off);
  if (off % PGSIZE || len == 0) return -EINVAL;
  if ((fd < 0 || f == NULL) && !(flags & MAP_ANONYMOUS)) return -EBADF;
  else if (flags & MAP_ANONYMOUS) { if (off != 0) return -EINVAL; f = NULL; }
  else if (f->type != FD_INODE) return -EPERM;
  if (!(flags & (MAP_SHARED|MAP_PRIVATE))) return -EINVAL;
  return do_mmap(start, len, prot, flags, f, off);
}

extern uint64 sys_mmap(void);
extern uint64 sys_munmap(void);
...
[SYS_mmap]  sys_mmap,
