enum segtype { NONE, LOAD, TEXT, DATA, BSS, HEAP, MMAP, STACK };
struct seg {
  enum segtype type; int flag; uint64 addr; uint64 sz;
  struct seg *next; uint64 mmap; uint64 f_off; uint64 f_sz;
};

uint64 do_mmap(uint64 start, uint64 len, int prot, int flags, struct file *f, int64 off) {
  ...
  if (flags & MAP_FIXED) ret = lookup_fixed_segment(start, start+sz, &prev, &new);
  else ret = lookup_segment(sz, &prev, &new);
  new->flag = (prot << 1) & (PTE_X|PTE_W|PTE_R);
  if (f) ret = mmap_file(new, len, flags, f, off);
  else ret = mmap_anonymous(new, flags);
  ...
  prev->next = new;
  return new->addr;
}

