}
void consoleintr(int c) {
    // handle special chars, echo, store to cons.buf
    cons.buf[cons.e++ % INPUT_BUF] = c;
    if(c == '\n' || c == C('D') || cons.e == cons.r+INPUT_BUF) {
        cons.w = cons.e;
        wakeup(&cons.r);
    }
}

int handle_intr(uint64 scause) {
    if (INTR_EXTERNAL == scause) {
        int irq = plic_claim();
        switch (irq) {
        case UART_IRQ:
            c = sbi_console_getchar();
            if (-1 != c) consoleintr(c);
            break;
        case DISK_IRQ:
            disk_intr();
            break;
        }
        if (irq) plic_complete(irq);
    }
}

#ifdef QEMU
#define UART_IRQ    10
#define DISK_IRQ    1
#else
#define UART_IRQ    33
#define DISK_IRQ    27
#endif
void plicinit(void);
void plicinithart(void);
int plic_claim(void);
void plic_complete(int irq);

void plicinit(void) {
    writed(1, PLIC_V + DISK_IRQ * sizeof(uint32));
    writed(1, PLIC_V + UART_IRQ * sizeof(uint32));
}
void plicinithart(void) {
    int hart = cpuid();
    #ifdef QEMU
    *(uint32*)PLIC_SENABLE(hart) = (1 << UART_IRQ) | (1 << DISK_IRQ);
    *(uint32*)PLIC_SPRIORITY(hart) = 0;
    #else
    uint32 *hart_m_enable = (uint32*)PLIC_MENABLE(hart);
    *(hart_m_enable) = readd(hart_m_enable) | (1 << DISK_IRQ);
    *(hart0_m_int_enable_hi) = readd(hart0_m_int_enable_hi) | (1 << (UART_IRQ % 32));
    #endif
}

