	struct dentry		*entry;
};

struct kstat {
	...
	uint32    mode;
	uint32    nlink;
	uint32    uid;
	uint32    gid;
	...
};

// 在 sys_openat 中：
// 无权限检查调用
ilock(ip);
if (S_ISDIR(ip->mode) && (omode & (O_WRONLY|O_RDWR))) {
    iunlockput(ip);
    return -EISDIR;
}
if ((omode & O_DIRECTORY) && !S_ISDIR(ip->mode)) {
    iunlockput(ip);
    return -ENOTDIR;
}
// ...
f->readable = !(omode & O_WRONLY);
f->writable = (omode & O_WRONLY) || (omode & O_RDWR);
